# Deploy the full three-tier risk policy set
# Pre-requisites:
#   - Entra ID P2 license for all users
#   - SSPR enabled for all users
#   - MFA methods registered for all users (or MFA registration policy deployed first)
#   - Break-glass group exists and is populated

$breakGlassGroupId = '<break-glass-group-object-id>'

# 1. Block High Sign-in Risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA-IP-01: Block High Sign-in Risk'
    State = 'enabledForReportingButNotEnforcing'  # start report-only
    Conditions = @{
        Users = @{
            IncludeUsers = @('all')
            ExcludeGroups = @($breakGlassGroupId)
        }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('high')
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('block') }
}

# 2. MFA for Medium Sign-in Risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA-IP-02: MFA for Medium Sign-in Risk'
    State = 'enabledForReportingButNotEnforcing'
    Conditions = @{
        Users = @{
            IncludeUsers = @('all')
            ExcludeGroups = @($breakGlassGroupId)
        }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('medium')
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('mfa') }
}

# 3. Password Change for High User Risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA-IP-03: Password Change for High User Risk'
    State = 'enabledForReportingButNotEnforcing'
    Conditions = @{
        Users = @{
            IncludeUsers = @('all')
            ExcludeGroups = @($breakGlassGroupId)
        }
        Applications = @{ IncludeApplications = @('all') }
        UserRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'AND'
        BuiltInControls = @('mfa', 'passwordChange')
    }
}

Write-Host 'All three policies created in Report-Only mode. Monitor SigninLogs for 48h before enabling.'

# MFA registration policy: require unregistered users to register MFA on next sign-in
# This is separate from the Entra ID Protection 'MFA registration policy' (legacy)
# Use a CA policy targeting 'register security information' user action instead

# Find users without MFA registered
$unregistered = Get-MgReportAuthenticationMethodUserRegistrationDetail \
    -Filter 'isMfaRegistered eq false'
Write-Host "Users without MFA: $($unregistered.Count)"

# Create a CA policy requiring MFA for unregistered users attempting to register
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA-IP-00: Require MFA Registration'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{
            IncludeUserActions = @('urn:user:registerSecurityInfo')
        }
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('mfa') }
}
# Note: users who have no MFA method yet cannot satisfy this policy.
# For initial bootstrapping, use Temporary Access Pass (TAP) to enable first registration.

# Terraform: deploy the three risk-based CA policies
variable "break_glass_group_id" { type = string }

resource "azuread_conditional_access_policy" "block_high_signin_risk" {
  display_name = "CA-IP-01: Block High Sign-in Risk"
  state        = "enabledForReportingButNotEnforcing"

  conditions {
    users {
      included_users  = ["All"]
      excluded_groups = [var.break_glass_group_id]
    }
    applications { included_applications = ["All"] }
    client_app_types    = ["all"]
    sign_in_risk_levels = ["high"]
  }
  grant_controls {
    operator          = "OR"
    built_in_controls = ["block"]
  }
}

resource "azuread_conditional_access_policy" "mfa_medium_signin_risk" {
  display_name = "CA-IP-02: MFA for Medium Sign-in Risk"
  state        = "enabledForReportingButNotEnforcing"

  conditions {
    users {
      included_users  = ["All"]
      excluded_groups = [var.break_glass_group_id]
    }
    applications { included_applications = ["All"] }
    client_app_types    = ["all"]
    sign_in_risk_levels = ["medium"]
  }
  grant_controls {
    operator          = "OR"
    built_in_controls = ["mfa"]
  }
}

resource "azuread_conditional_access_policy" "password_change_high_user_risk" {
  display_name = "CA-IP-03: Password Change for High User Risk"
  state        = "enabledForReportingButNotEnforcing"

  conditions {
    users {
      included_users  = ["All"]
      excluded_groups = [var.break_glass_group_id]
    }
    applications { included_applications = ["All"] }
    client_app_types  = ["all"]
    user_risk_levels  = ["high"]
  }
  grant_controls {
    operator          = "AND"
    built_in_controls = ["mfa", "passwordChange"]
  }
}

# Emergency rollback: disable all CA-IP risk policies
# Use if a risk policy is causing widespread user lockouts

$ipPolicies = Get-MgIdentityConditionalAccessPolicy | Where-Object { $_.DisplayName -like 'CA-IP-*' }
foreach ($p in $ipPolicies) {
    Update-MgIdentityConditionalAccessPolicy -ConditionalAccessPolicyId $p.Id -State 'disabled'
    Write-Host "Disabled: $($p.DisplayName)"
}
Write-Host 'All CA-IP policies disabled. Investigate before re-enabling.'

# To roll back to Report-Only (less disruptive than full disable):
foreach ($p in $ipPolicies) {
    Update-MgIdentityConditionalAccessPolicy -ConditionalAccessPolicyId $p.Id \
        -State 'enabledForReportingButNotEnforcing'
}
